def gen(rng, size):
    n = max(1, min(size, 100))
    nums = []
    while len(nums) < n:
        if rng.random() < 0.3:
            nums.append(rng.randint(1, 100))
        else:
            run = rng.randint(1, 5)
            for _ in range(run):
                if len(nums) < n:
                    nums.append(-1)
    return [nums]

