class Solution:
    def lastVisitedIntegers(self, nums):
        seen = []
        ans = []
        streak = 0
        for x in nums:
            if x == -1:
                streak += 1
                if streak <= len(seen):
                    ans.append(seen[streak - 1])
                else:
                    ans.append(-1)
            else:
                streak = 0
                seen.insert(0, x)
        return ans

