var lastVisitedIntegers = function(nums) {
    const seen = [];
    const ans = [];
    let streak = 0;
    for (const x of nums) {
        if (x === -1) {
            streak += 1;
            if (streak <= seen.length) {
                ans.push(seen[seen.length - streak]);
            } else {
                ans.push(-1);
            }
        } else {
            streak = 0;
            seen.push(x);
        }
    }
    return ans;
};
